import React from 'react'
import styles from './styles.module.css'

export default function about() {
    return (
        <div className="container">
            <h1 className={styles.category}>Biography</h1>
            <p>(1978 - ) Ryan Kueter is a professional Software Developer with a focus on C# .NET Core and Node.js web technologies. His work involves applying design principles, data structures, and capacity planning to build systems that are maintainable, extensible, scalable, recoverable, robust, and secure. His background is in systems administration in Windows Server technologies, including Active Directory, Group Policy, virtualization, switches, and Linux.</p>
        </div>
    )
}
